    const gridToCartn = Grid.getGridToCartesianTransform(volume.grid);
    const isoVal = Volume.IsoValue.toAbsolute(props.isoValue, stats).absoluteValue;
    const p = Vec3();
    const [xn, yn, zn] = space.dimensions;
